  ('PULSE LAGOS', 'Sat, Jul 5', '10 PM – 4 AM', 'Quilox Club, Victoria Island', '15 Ozumba Mbadiwe Ave, Victoria Island, Lagos', 6.4281, 3.4219, '₦15,000', 15000, 2.3, 'Club', 1000, 423, '18+', 'Smart Casual', 'Flytime Music', '@flytime_music', '+2348012345678', 'Lagos''s most electrifying club night featuring top DJs spinning Afrobeats, Amapiano & more. 3 floors of pure energy — VIP tables available.', 'linear-gradient(135deg,#7C4FE0 0%,#552CB7 100%)', true, true),
